import { Component, ViewChild } from '@angular/core';
import { FormGroup, FormBuilder, Validators } from '@angular/forms';
import { MatPaginator } from '@angular/material/paginator';
import { MatSort } from '@angular/material/sort';
import { delay, map, merge, startWith, switchMap, tap } from 'rxjs';
import { ApiService } from '@services/api.service';

@Component({
  selector: 'app-productslist',
  templateUrl: './productslist.component.html',
  styleUrls: ['./productslist.component.scss']
})
export class ProductslistComponent {

  query: string = "";
  filterForm: FormGroup;
  isLoadingResults = true;

  displayedColumns: string[] = ['product_id', 'product_name', 'Product Price', 'Store Name', 'Action'];
  data : Product[] = [];
  resultsLength = 0;
  sortBy: string = 'product_id'
  stores: string[] = [];

  @ViewChild(MatPaginator) paginator: MatPaginator;
  @ViewChild(MatSort) sort: MatSort;

  ngOnInit(): void {

  }
  
  constructor(private api: ApiService, private fb: FormBuilder) {
    this.filterForm = this.fb.group({
      q: ['', ]
    })

    this.filterForm.valueChanges.pipe(
      tap(() => this.isLoadingResults = true),
      delay(1000)
    ).subscribe(() => {
      this.api.productList(this.query, [], this.paginator.pageIndex + 1, this.paginator.pageSize, this.sort.active, this.sort.direction).subscribe((data: any) => {
        this.isLoadingResults = false;
        if (data === null) {
          return [];
        }
  
        this.resultsLength = data.total_count;
        this.data = data.products.map((product:any) => {
          return {
            store_id: product.store.store_id,
            product_id: product.product_id,
            product_name: product.product_name,
            product_price: product.product_price,
            store_name: product.store.store_name,
          }
        });
      })
    })

  }

 
  ngAfterViewInit() {
    this.sort.sortChange.subscribe(() => {
      this.paginator.pageIndex = 0
    });

    merge(this.sort.sortChange, this.paginator.page)
      .pipe(
        startWith({}),
        switchMap(() => {
          this.isLoadingResults = true;
          return this.api.productList(this.query, [], this.paginator.pageIndex+1, this.paginator.pageSize, this.sort.active, this.sort.direction);
        }),
        map((data: any) => {
          this.isLoadingResults = false;
          // Flip flag to show that loading has finished.
          if (data === null) {
            return [];
          }

          this.resultsLength = data.total_count;
          return data.products.map((product:any) => {
        
            return {
              store_id: product.store.store_id,
              product_id: product.product_id,
              product_name: product.product_name,
              product_price: product.product_price,
              store_name: product.store.store_name,
            }
          });
        }),
      )
      .subscribe(data => this.data = data);

  }

}


export interface Product {
  store_id: string;
  product_id: string,
  product_name: string,
  product_price: number,
  store_name: string
  
}