import { Component } from '@angular/core';
import {CdkDragDrop, moveItemInArray} from '@angular/cdk/drag-drop';
import { Form, FormArray, FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';
import { ApiService } from '@services/api.service';
import {pipe, delay, tap, debounce, debounceTime, catchError} from 'rxjs'
import { ToastrService } from 'ngx-toastr';
import { Router } from '@angular/router';

@Component({
  selector: 'app-createproducts',
  templateUrl: './createproducts.component.html',
  styleUrls: ['./createproducts.component.scss']
})
export class CreateproductsComponent {
  isLoading: boolean = false;

  productImages: ProductImage[] = [];
  productContents: ProductContent[] = [];
  productLinks: ProductLink[] = [];

  stores: Store[] = [];
  selectedStore: Store;
  storeId: string;
  product_id: string;

  storeCategories: ProductCategory[] = []
  quantityTypes: QuantityType[] = []

  productForm: FormGroup
  storeForm: FormGroup


  constructor(
    private fb: FormBuilder,
    private api: ApiService,
    private toastr: ToastrService,
    private router: Router
  ) {
    this.productForm = this.fb.group({
      store_id: ['', Validators.required],
      product: this.fb.group({
        quantity_type_id: ['1', [Validators.required]],
        quantity: [0, [Validators.required]],
        is_featured_product: [false, [Validators.required]],
        product_name: ['', [Validators.required]],
        description: ['', []],
        product_price: [0.0, [Validators.required]],
        selling_price: [0.0, [Validators.required]],
        discount_type: ['percentage', [Validators.required]],
        discount_value: [0.0, [Validators.required]],
        is_product_returnable: [false, [Validators.required]],
        return_days_count: [0, [Validators.required]],
        length: [0.0, []],
        width: [0.0, []],
        height: [0.0, []],
        weight: [0.0, [Validators.required]],
        is_enabled: [false, [Validators.required]],
      }),
      product_categories: this.fb.array([
        this.fb.group({
          category_id: ['', []]
        })
      ]),
      product_images: this.fb.array([
        
      ]),
      product_contents: this.fb.array([
        
      ]),
      product_links: this.fb.array([
        
      ])
    })

    this.storeForm = this.fb.group({
      store_name: ['', [Validators.required]]
    })

    this.storeForm.valueChanges.pipe(
      debounceTime(500),
      tap(() => {
        this.listStores(this.storeForm.value.store_name);
      })
    ).subscribe();
    
    this.listStores(this.storeForm.value.store_name);
    this.listQuantityTypes();
  }

  ngOnInit() {
    
  }

  changeStore(store: Store) {
    this.selectedStore = store; 
    this.productForm.value.store_id = store.store_id;
    this.storeId = store.store_id
    this.listCategories();
  }

  //images
  addImageTile() {
    const order = this.productImages.length+1
    this.productImages.push({image_url: '', dynamic_url: '', order})
    const fa = this.productForm.controls.product_images as FormArray
    fa.push(this.fb.group({
      image_url: ['', [Validators.required]],
      order: [order, [Validators.required]]
    }))
  }

  removeImage(i: number) {
    this.productImages = this.productImages.filter((pi, index: number) => i != index )
    const fa = this.productForm.controls.product_images as FormArray
    fa.removeAt(i)
  }

  dropImage(event: CdkDragDrop<ProductImage[]>) {
    moveItemInArray(this.productImages, event.previousIndex, event.currentIndex);
    for(let i=0; i<this.productImages.length; i++) {
      const fa = this.productForm.controls.product_images as FormArray
      const fg = fa.controls.find((pi) => pi.value.image_url == this.productImages[i].image_url)
      fg.setValue({image_url: this.productImages[i].image_url, order: i+1})
    }
  }

  uploadImage(evt: any, index: number) {
    if(!evt.target.files[0]) {
      return
    }
    const sub = this.api.uploadSingleFile(evt.target.files[0]).subscribe((response: any) => {
      sub.unsubscribe();
      this.productImages[index].image_url = response.urls.orignal_url;
      this.productImages[index].dynamic_url = response.urls.dynamic_url;
      const fa = this.productForm.controls.product_images as FormArray
      fa.controls[index].setValue({image_url: this.productImages[index].image_url, order: this.productImages[index].order})
    })
  }

  addContentTile() {
    const order = this.productContents.length+1
    this.productContents.push({heading: '', paragraph: '', order: order})
    const fa = this.productForm.controls.product_contents as FormArray
    fa.push(this.fb.group({
      heading: ['', [Validators.required]],
      paragraph: ['', [Validators.required]],
      order: [order, [Validators.required]]
    }))
  }

  removeContent(i: number) {
    this.productContents = this.productContents.filter((pc, index: number) => i != index )
    const fa = this.productForm.controls.product_contents as FormArray
    fa.removeAt(i)
  }

  dropContent(event: CdkDragDrop<ProductContent[]>) {
    moveItemInArray(this.productContents, event.previousIndex, event.currentIndex);
    for(let i=0; i<this.productContents.length; i++) {
      const fa = this.productForm.controls.product_contents as FormArray
      const fg = fa.controls.find((pc) => pc.value.heading == this.productContents[i].heading && pc.value.paragraph == this.productContents[i].paragraph)
      fg.setValue({heading: this.productContents[i].heading, paragraph: this.productContents[i].paragraph, order: i+1})
    }
  }

  addLinkTile() {
    const order = this.productLinks.length+1
    this.productLinks.push({name: '', link: '', order})
    const fa = this.productForm.controls.product_links as FormArray
    fa.push(this.fb.group({
      name: ['', [Validators.required]],
      link: ['', [Validators.required]],
      order: [order, [Validators.required]]
    }))
  }

  removeLink(i: number) {
    this.productLinks = this.productLinks.filter((pl, index: number) => i != index )
    const fa = this.productForm.controls.product_links as FormArray
    fa.removeAt(i)
  }

  dropLink(event: CdkDragDrop<ProductLink[]>) {
    moveItemInArray(this.productLinks, event.previousIndex, event.currentIndex);
    for(let i=0; i<this.productLinks.length; i++) {
      const fa = this.productForm.controls.product_links as FormArray
      const fg = fa.controls.find((pc) => pc.value.name == this.productLinks[i].name && pc.value.link == this.productLinks[i].link)
      fg.setValue({name: this.productLinks[i].name, link: this.productLinks[i].link, order: i+1})
    }
  }

  listStores(q: string) {
    const sub = this.api.listStores(q, 1, 100, 'store_id', 'DESC').subscribe((response: any) => {
      sub.unsubscribe()
      this.stores = response.stores.map(({store_name, store_id}) => {
        return {store_name, store_id}
      })
    })
  }


  listCategories() {
    const sub = this.api.categoryList('', 1, 100, "category_id", "DESC", [{store_id: this.productForm.value.store_id}]).subscribe((response: any) => {
        sub.unsubscribe()
        this.storeCategories = response.categories.map(({category_id, category_name}) => {return {category_id, category_name}})
    })
  }

  listQuantityTypes() {
    const sub = this.api.listQuantityTypes().subscribe((response: any) => {
      sub.unsubscribe();
      this.quantityTypes = response.quantity_types.map(({quantity_type_id, quantity_type_name}) => {return {quantity_type_id, quantity_type_name}})
    })
  }


  createProduct() {
    if(this.productForm.invalid) {
      return alert("Please fill all mandatory fields");
    }

    const productCategories = this.productForm.value.product_categories[0].category_id ? this.productForm.value.product_categories : [];
    const values = this.productForm.value;
    if(values.product.product_price <= 0) {
      return alert("Product price must not be less than or equals to 0")
    }
    const sub = this.api.createProduct(values.store_id,{...values.product, selling_price: values.product.product_price},productCategories,values.product_images,values.product_contents,values.product_links)
    .pipe(
      catchError(err => {
        return err;
      })
    )
    .subscribe((response: any) => {
      sub.unsubscribe();
      if(response?.status >= 400) {
        this.toastr.error(response.error.message)
        return;
      }
      this.toastr.success(response.message);
      this.router.navigate(['/products']);
    })
  }

  deleteProduct() {
    const sub = this.api.deleteProduct(this.storeId, this.product_id)
    .pipe(
      catchError(err => {
        return err;
      })
    )
    .subscribe((response: any) => {
      sub.unsubscribe();
      if(response?.status >= 400) {
        this.toastr.error(response.error.message)
        return;
      }
      this.toastr.success(response.message);
      this.router.navigate(['/products']);
    })
  }


}





interface Store {
  store_id: string;
  store_name: string;
}


interface QuantityType {
  quantity_type_id: string;
  quantity_type_name: string;
}


interface ProductCategory {
  category_type_id: string;
  category_type_name: string;
}

interface ProductImage {
  image_url: string;
  dynamic_url: string;
  order: number;
}

interface ProductContent {
  heading: string;
  paragraph: string;
  order: number;
}

interface ProductLink {
  name: string;
  link: string;
  order: number;
}


interface Product {
  quantity_type_id: number; 
  quantity: number; 
  is_featured_product: boolean, 
  product_name: string,
  description: string, 
  product_price: string, 
  selling_price: string, 
  discount_type: string, 
  discount_value: number,
  is_product_returnable: true, 
  return_days_count: number, 
  length: string, 
  width: string, 
  height: string, 
  weight: string,
  is_enabled: boolean
}

