import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { BulkCreateProductsComponent } from './bulk-create-products/bulk-create-products.component';
import { CreateproductsComponent } from './createproducts/createproducts.component';
import { EditProductComponent } from './edit-product/edit-product.component';
import { ProductslistComponent } from './productslist/productslist.component';

const routes: Routes = [
  {path: '', component: ProductslistComponent},
  {path: 'create', component: CreateproductsComponent},
  {path: 'update/:store_id/:product_id', component: EditProductComponent},
  {path: 'bulkcreate', component: BulkCreateProductsComponent}


];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class ProductsRoutingModule { }
