import { Component } from '@angular/core';
import {CdkDragDrop, moveItemInArray} from '@angular/cdk/drag-drop';
import { Form, FormArray, FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';
import { ApiService } from '@services/api.service';
import {pipe, delay, tap, debounce, debounceTime, catchError} from 'rxjs'
import { ToastrService } from 'ngx-toastr';
import { ActivatedRoute, Router } from '@angular/router';


@Component({
  selector: 'app-edit-product',
  templateUrl: './edit-product.component.html',
  styleUrls: ['./edit-product.component.scss']
})
export class EditProductComponent {

  isLoading: boolean = true;

  productImages: ProductImage[] = [];
  productContents: ProductContent[] = [];
  productLinks: ProductLink[] = [];

  selectedStore: Store;
  storeId: string;
  productId: string

  storeCategories: ProductCategory[] = []
  productCategories: any[] = []

  quantityTypes: QuantityType[] = []

  productForm: FormGroup


  constructor(
    private fb: FormBuilder,
    private api: ApiService,
    private toastr: ToastrService,
    private router: Router,
    private route: ActivatedRoute
  ) {
    this.productForm = this.fb.group({
      store_id: ['', Validators.required],
      product: this.fb.group({
        product_id: ['', [Validators.required]],
        quantity_type_id: ['1', [Validators.required]],
        quantity: [0, [Validators.required]],
        is_featured_product: [false, [Validators.required]],
        product_name: ['', [Validators.required]],
        description: ['', []],
        product_price: [0.0, [Validators.required]],
        selling_price: [0.0, [Validators.required]],
        discount_type: ['percentage', [Validators.required]],
        discount_value: [0.0, [Validators.required]],
        is_product_returnable: [false, [Validators.required]],
        return_days_count: [0, [Validators.required]],
        length: [0.0, []],
        width: [0.0, []],
        height: [0.0, []],
        weight: [0.0, [Validators.required]],
        is_enabled: [false, [Validators.required]],
      }),
      product_categories: [[]],
      product_images: this.fb.array([
        
      ]),
      product_contents: this.fb.array([
        
      ]),
      product_links: this.fb.array([
        
      ])
    })

    this.listQuantityTypes();
  }

  ngOnInit() {
    this.route.paramMap.subscribe((params) => {
      this.storeId = params.get('store_id');
      this.productId = params.get('product_id')
      this.getProductDetails(params.get('product_id'), this.storeId);
      this.getStoreDetails(this.storeId);
      this.listCategories();
    })
  }

  getProductDetails(product_id: string, store_id: string) {
    const sub = this.api.productDetails(store_id, product_id).subscribe((response: any) => {
      this.isLoading = false
      sub.unsubscribe();

      const product = response.product;

      //store
      //store
      //store
      //store
      this.productForm.controls.store_id.setValue(product.store_id)

      //product
      //product
      //product
      //product
      this.productForm.controls.product.setValue({
        product_id: product.product_id,
        quantity_type_id: product.quantity_type_id,
        quantity:product.quantity,
        is_featured_product: product.is_featured_product,
        product_name: product.product_name,
        description: product.description,
        product_price: product.product_price,
        selling_price: product.selling_price,
        discount_type: product.discount_type,
        discount_value: product.discount_value,
        is_product_returnable: product.is_product_returnable,
        return_days_count: product.return_days_count,
        length: product.length,
        width: product.width,
        height: product.height,
        weight: product.weight,
        is_enabled: product.is_enabled,
      });

      //product category
      //product category
      //product category
      //product category
      if(product.product_categories.length) {
        this.productCategories = product.product_categories;
        this.productForm.controls.product_categories.setValue(this.productCategories.map(pc => pc.category.category_id))
      }


      //product images
      //product images
      //product images
      //product images
      const productImages = product.product_images.map((pi) => {
        return {
          product_image_id: pi.product_image_id,
          order: pi.order,
          status: pi.status,
          image_url: pi.image.orignal_url,
          dynamic_url: pi.image.dynamic_url,
        }
      });
      productImages.forEach(pi => {
        this.addImageTile(pi.product_image_id, pi.status, pi.image_url, pi.dynamic_url, pi.order)
      });
      //product content
      //product content
      //product content
      //product content
      const productContents = product.product_contents.map((pi) => {
        return {
          product_content_id: pi.product_content_id,
          heading: pi.heading,
          paragraph: pi.paragraph,
          order: pi.order,
          status: pi.status,
        }
      });
      productContents.forEach(pi => {
        this.addContentTile(pi.product_content_id, pi.status, pi.heading, pi.paragraph, pi.order)
      });
      //product link
      //product link
      //product link
      //product link
      const productLinks = product.product_links.map((pl) => {
        return {
          product_link_id: pl.product_link_id,
          name: pl.name,
          link: pl.link,
          order: pl.order,
          status: pl.status,
        }
      });
      productLinks.forEach(pl => {
        this.addLinkTile(pl.product_link_id, pl.status, pl.name, pl.link, pl.order)
      });
    })
  }

  getStoreDetails(store_id: string) {
    const sub = this.api.getStoreDetails(store_id).subscribe((response: any) => {
      sub.unsubscribe();
      this.selectedStore = {
        store_id,
        store_name: response.store.store_name
      }
    })
  }

  //images
  addImageTile(product_image_id: null | string, status: 'active'|'deleted', image_url: string, dynamic_url: string, order?: number) {
    order = order ? order : this.productImages.length+1
    this.productImages.push({product_image_id, status, image_url, dynamic_url, order})
    const fa = this.productForm.controls.product_images as FormArray
    fa.push(this.fb.group({
      product_image_id: [product_image_id, []],
      image_url: [image_url, [Validators.required]],
      order: [order, [Validators.required]],
      status: [status, [Validators.required]]
    }))
  }

  removeImage(i: number) {
    this.productImages[i].status = 'deleted';
    const fa = this.productForm.controls.product_images as FormArray
    fa.controls[i].setValue({...fa.controls[i].value, status: 'deleted'})
  }

  dropImage(event: CdkDragDrop<ProductImage[]>) {
    moveItemInArray(this.productImages, event.previousIndex, event.currentIndex);
    for(let i=0; i<this.productImages.length; i++) {
      const fa = this.productForm.controls.product_images as FormArray
      const fg = fa.controls.find((pi) => pi.value.image_url == this.productImages[i].image_url)
      fg.setValue({...fg.value, order: i+1})
    }
  }

  uploadImage(evt: any, index: number) {
    if(!evt.target.files[0]) {
      return
    }
    this.isLoading = true;
    const sub = this.api.uploadSingleFile(evt.target.files[0]).subscribe((response: any) => {
      sub.unsubscribe();
      this.productImages[index].image_url = response.urls.orignal_url;
      this.productImages[index].dynamic_url = response.urls.dynamic_url;
      const fa = this.productForm.controls.product_images as FormArray
      fa.controls[index].setValue({product_image_id: this.productImages[index].product_image_id, status: this.productImages[index].status, image_url: this.productImages[index].image_url, order: this.productImages[index].order})
      this.isLoading = false;
    })
  }

  addContentTile(product_content_id: null|string, status: 'active'|'deleted', heading: string, paragraph: string, order?: number) {
    order = order ? order : this.productContents.length+1
    this.productContents.push({product_content_id, status, heading, paragraph, order})
    const fa = this.productForm.controls.product_contents as FormArray
    fa.push(this.fb.group({
      product_content_id: [product_content_id, [Validators.required]],
      status: [status, [Validators.required]],
      heading: [heading, [Validators.required]],
      paragraph: [paragraph, [Validators.required]],
      order: [ order, [Validators.required]]
    }))
  }

  removeContent(i: number) {
    this.productContents[i].status = 'deleted';
    const fa = this.productForm.controls.product_contents as FormArray
    fa.controls[i].setValue({...fa.controls[i].value, status: 'deleted'})
  }

  dropContent(event: CdkDragDrop<ProductContent[]>) {
    moveItemInArray(this.productContents, event.previousIndex, event.currentIndex);
    for(let i=0; i<this.productContents.length; i++) {
      const fa = this.productForm.controls.product_contents as FormArray
      const fg = fa.controls.find((pc) => pc.value.heading == this.productContents[i].heading && pc.value.paragraph == this.productContents[i].paragraph && pc.value.product_content_id == this.productContents[i].product_content_id)
      fg.setValue({product_content_id: this.productContents[i].product_content_id, status: this.productContents[i].status, heading: this.productContents[i].heading, paragraph: this.productContents[i].paragraph, order: i+1})
    }
  }

  addLinkTile(product_link_id:null|string, status: 'active'|'deleted', name:string, link:string, order?: number) {
    order = order ? order : this.productLinks.length+1
    this.productLinks.push({ product_link_id, status, name, link, order})
    const fa = this.productForm.controls.product_links as FormArray
    fa.push(this.fb.group({
      product_link_id: [product_link_id, []],
      name: [name, [Validators.required]],
      link: [link, [Validators.required]],
      order: [order, [Validators.required]],
      status: [status, [Validators.required]]
    }))
  }

  removeLink(i: number) {
    this.productLinks[i].status = 'deleted';
    const fa = this.productForm.controls.product_links as FormArray
    fa.controls[i].setValue({...fa.controls[i].value, status: 'deleted'})
  }

  dropLink(event: CdkDragDrop<ProductLink[]>) {
    moveItemInArray(this.productLinks, event.previousIndex, event.currentIndex);
    for(let i=0; i<this.productLinks.length; i++) {
      const fa = this.productForm.controls.product_links as FormArray
      const fg = fa.controls.find((pc) => pc.value.name == this.productLinks[i].name && pc.value.link == this.productLinks[i].link)
      fg.setValue({...this.productLinks[i], order: i+1})
    }
  }


  listCategories() {
    const sub = this.api.categoryList('', 1, 100, "category_id", "DESC", [{store_id: this.storeId}]).subscribe((response: any) => {
        sub.unsubscribe()
        this.storeCategories = response.categories.map(({category_id, category_name}) => {return {category_id, category_name}})
    })
  }

  listQuantityTypes() {
    const sub = this.api.listQuantityTypes().subscribe((response: any) => {
      sub.unsubscribe();
      this.quantityTypes = response.quantity_types.map(({quantity_type_id, quantity_type_name}) => {return {quantity_type_id, quantity_type_name}})
    })
  }


  updateProduct() {
    if(this.productForm.invalid) {
      return alert("Please fill all mandatory fields");
    }
    this.isLoading = true;

    const productCategories = [];
    this.productForm.value.product_categories.forEach((category_id) => {
      const productCategory = this.productCategories.find((pc: any) => {return pc.category.category_id == category_id})
      if(productCategory) {
        productCategories.push(productCategory)
      }else{
        productCategories.push({
          product_category_id: null,
          status: 'active',
          category: {
            category_id
          }
        })
      }
    })

    this.productCategories.forEach((pc: any) => {
      const productCategory = productCategories.find((p: any) => {
        return p.category.category_id == pc.category.category_id
      })

      if(!productCategory) {
        productCategories.push({...pc, status: 'deleted'})
      }
    })
    
    const values = this.productForm.value;
    
    let lastImageIndex = 0;
    const productImages = values.product_images.map((pi) => {
      if(pi.status == 'active') {
        return {
          ...pi, order: ++lastImageIndex
        }
      }
      return pi;
    })

    let lastContentIndex = 0;
    const productContents = values.product_contents.map((pc) => {
      if(pc.status == 'active') {
        return {
          ...pc, order: ++lastContentIndex
        }
      }
      return pc;
    })

    let lastLinkIndex = 0;
    const productLinks = values.product_links.map((pl) => {
      if(pl.status == 'active') {
        return {
          ...pl, order: ++lastLinkIndex
        }
      }
      return pl;
    })

    const sub = this.api.updateProduct(values.store_id,{...values.product, selling_price: values.product.product_price},productCategories,productImages,productContents,productLinks)
    .pipe(
      catchError(err => {
        return err;
      })
    )
    .subscribe((response: any) => {
      this.isLoading = false;
      sub.unsubscribe();
      if(response?.status >= 400) {
        this.toastr.error(response.error.message)
        return;
      }
      this.toastr.success(response.message);
      this.router.navigate(['/products']);
    })
  }

  deleteProduct() {
    const sub = this.api.deleteProduct(this.storeId, this.productId)
    .pipe(
      catchError(err => {
        return err;
      })
    )
    .subscribe((response: any) => {
      sub.unsubscribe();
      if(response?.status >= 400) {
        this.toastr.error(response.error.message)
        return;
      }
      this.toastr.success(response.message);
      this.router.navigate(['/products']);
    })
  }


}





interface Store {
  store_id: string;
  store_name: string;
}


interface QuantityType {
  quantity_type_id: string;
  quantity_type_name: string;
}


interface ProductCategory {
  category_type_id: string;
  category_type_name: string;
}

interface ProductImage {
  product_image_id: null | string;
  image_url: string;
  dynamic_url: string;
  order: number;
  status: 'active' | 'deleted';
}

interface ProductContent {
  product_content_id: string | null;
  heading: string;
  paragraph: string;
  order: number;
  status: 'active' | 'deleted';
}

interface ProductLink {
  product_link_id: string | null;
  name: string;
  link: string;
  order: number;
  status: 'active' | 'deleted';
}


interface Product {
  quantity_type_id: number; 
  quantity: number; 
  is_featured_product: boolean, 
  product_name: string,
  description: string, 
  product_price: string, 
  selling_price: string, 
  discount_type: string, 
  discount_value: number,
  is_product_returnable: true, 
  return_days_count: number, 
  length: string, 
  width: string, 
  height: string, 
  weight: string,
  is_enabled: boolean
}

